# Load all business data
businesses_data = locals().get('var_functions.query_db:24', [])

# Extract business categories from descriptions and count which ones accept credit cards
category_counts = {}
credit_card_business_ids = []

# First, identify all businesses that accept credit cards
for business in businesses_data:
    attributes = business.get('attributes', {})
    if isinstance(attributes, dict):
        if attributes.get('BusinessAcceptsCreditCards') == 'True':
            credit_card_business_ids.append(business.get('business_id'))

# Extract categories from descriptions
for business in businesses_data:
    if business.get('business_id') in credit_card_business_ids:
        description = business.get('description', '')
        # Look for categories mentioned in description (typically after "services in" or similar)
        if 'services in' in description:
            # Extract text after "services in"
            categories_text = description.split('services in')[1]
            # Split by commas to get individual categories
            categories = [cat.strip() for cat in categories_text.split(',')]
            for category in categories:
                if 'and' in category:
                    # Handle "and" before last category
                    parts = category.split('and')
                    for part in parts:
                        cat = part.strip()
                        if cat and cat.endswith('.'):
                            cat = cat[:-1]
                        if cat:
                            category_counts[cat] = category_counts.get(cat, 0) + 1
                else:
                    cat = category
                    if cat.endswith('.'):
                        cat = cat[:-1]
                    if cat:
                        # Special case for "Beauty & Spas" - standardize
                        if 'Beauty & Spas' in cat or ('Beauty' in cat and 'Spas' in cat):
                            category_counts['Beauty & Spas'] = category_counts.get('Beauty & Spas', 0) + 1
                        elif 'Hair Salons' in cat or 'Hair Removal' in cat or 'Nail Salons' in cat:
                            category_counts['Beauty & Spas'] = category_counts.get('Beauty & Spas', 0) + 1
                        elif 'Makeup Artists' in cat or 'Blow Dry' in cat or 'Cosmetics' in cat:
                            category_counts['Beauty & Spas'] = category_counts.get('Beauty & Spas', 0) + 1
                        elif 'Gun/Rifle Ranges' in cat:
                            category_counts['Active Life'] = category_counts.get('Active Life', 0) + 1
                        else:
                            category_counts[cat] = category_counts.get(cat, 0) + 1

result = {
    'credit_card_businesses': len(credit_card_business_ids),
    'category_counts': category_counts,
    'categories': list(category_counts.items())
}

print('__RESULT__:')
print(json.dumps(result))"}
